import React from 'react';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import Home from './components/Home';
import Upload from './components/Upload';
import Result from './components/Result';
import ImageProject from './components/ImageProject';
import AudioProject from './components/AudioProject';
import PoseProject from './components/PoseProject';

const App = () => {
    return (
        <Router>
            <div>
                <nav>
                    {/* Add navigation links */}
                </nav>

                <Switch>
                    <Route exact path="/" component={Home} />
                    <Route path="/upload" component={Upload} />
                    <Route path="/result" component={Result} />
                    <Route path="/image-project" component={ImageProject} />
                    <Route path="/audio-project" component={AudioProject} />
                    <Route path="/pose-project" component={PoseProject} />
                </Switch>
            </div>
        </Router>
    );
};

export default App;
